func slowSum(_ n: Int) -> Int {
    var total = 0
    for i in 1...n {
        total += i
    }
    return total
}

func fastSum(_ n: Int) -> Int {
    return n * (n + 1) / 2
}

print("Slow: \(slowSum(1000))")
print("Fast: \(fastSum(1000))")

